// Agrupa as pendencias por UNIDADE.
// Cada item da fonte traz: unidade, email do responsavel, nome do responsavel
// e o link do quadro de tarefas (kanban) onde a pendencia deve ser tratada.
const response = $input.first().json;
const itens = Array.isArray(response.value) ? response.value : (Array.isArray(response) ? response : []);

if (itens.length === 0) {
  return [{ json: { temPendencias: false, grupos: [] } }];
}

const agrupado = itens.reduce((acc, item) => {
  const unidade = (item.unidade || 'Desconhecida').toString().trim();

  if (!acc[unidade]) {
    acc[unidade] = {
      nomeUnidade: unidade,
      email: (item.emailResponsavel || '').toString().trim(),
      nomeResponsavel: (item.nomeResponsavel || 'Responsavel').toString().trim(),
      linkQuadro: (item.linkQuadro || '').toString().trim(),
      qtd: 0
    };
  }
  acc[unidade].qtd++;
  return acc;
}, {});

// Ignora unidades sem email valido ou sem link do quadro
const log = [];
const grupos = Object.values(agrupado).filter(g => {
  if (!g.email.includes('@')) {
    log.push(`[IGNORADA] Sem email: ${g.nomeUnidade}`);
    return false;
  }
  if (!g.linkQuadro) {
    log.push(`[IGNORADA] Sem link do quadro: ${g.nomeUnidade}`);
    return false;
  }
  return true;
});

if (log.length) console.log(log.join('\n'));
console.log(`[INFO] ${grupos.length} unidade(s) com pendencias em aberto para envio.`);

return [{ json: { temPendencias: grupos.length > 0, grupos } }];

// Transforma cada grupo (unidade) em um item separado para gerar um e-mail por unidade.
const data = $input.first().json;

if (!data || !data.grupos || !data.grupos.length) return [];

return data.grupos.map(g => ({
  json: {
    nomeUnidade: g.nomeUnidade,
    email: g.email,
    linkQuadro: g.linkQuadro,
    nomeResponsavel: g.nomeResponsavel,
    qtdPendencias: g.qtd
  }
}));
